from datetime import datetime, timezone

from dns_de_rte_orchestrator.erasure_request import (
    ErasureDetailKey,
    ErasureRequest,
    ErasureState,
)


def make_request(
    id: str = "req-123",
    source: str = "test_source",
    state: ErasureState = "new",
    date_issued: datetime | None = None,
    erasure_details: dict[ErasureDetailKey, str] | None = None,
) -> ErasureRequest:
    if erasure_details is None:
        erasure_details = {"email": "user@example.com"}

    if date_issued is None:
        date_issued = datetime(2023, 1, 1, 12, 0, 0, tzinfo=timezone.utc)

    return ErasureRequest(
        id=id,
        source=source,
        state=state,
        date_issued=date_issued,
        erasure_details=erasure_details,
    )


def test_date_issued_ms_is_unix_ms():
    req = make_request()
    # 2023-01-01T12:00:00Z -> 1672574400 seconds -> 1672574400000 ms
    assert req.date_issued_ms == 1672574400000


def test_safe_dict_excludes_erasure_details():
    req = make_request()
    safe = req._safe_dict()  # pyright: ignore[reportPrivateUsage]
    assert "erasure_details" not in safe
    assert set(safe.keys()) == {"id", "source", "state", "date_issued"}


def test_str_and_repr_do_not_contain_sensitive_details():
    req = make_request()
    s = str(req)
    r = repr(req)

    # The sensitive erasure details should not be present in the string/repr
    assert "erasure_details" not in s
    assert "user@example.com" not in s

    assert "erasure_details" not in r
    assert "user@example.com" not in r

